# Shape definitions module - provides base classes and interfaces

enum ShapeType:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3

interface IShape:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

interface IColorable:
    def get_color(self) -> str: ...
    def set_color(self, new_color: str) -> None: ...

@abstract
class ShapeBase:
    _shape_type: ShapeType

    def __init__(self, shape_type: ShapeType):
        self._shape_type = shape_type

    def get_type(self) -> ShapeType:
        return self._shape_type

    def describe(self) -> str:
        type_val: int = self._shape_type.value
        return f"Shape of type {type_val}"

    @abstract
    def scale(self, factor: float) -> None: ...

class Circle(ShapeBase, IShape, IColorable):
    _radius: float
    _color: str

    def __init__(self, radius: float):
        super().__init__(ShapeType.CIRCLE)
        self._radius = radius
        self._color = "blue"

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self._radius

    @override
    def scale(self, factor: float) -> None:
        self._radius = self._radius * factor

    @override
    def get_color(self) -> str:
        return self._color

    @override
    def set_color(self, new_color: str) -> None:
        self._color = new_color

    def get_radius(self) -> float:
        return self._radius

class Rectangle(ShapeBase, IShape):
    width: float
    height: float

    def __init__(self, w: float, h: float):
        super().__init__(ShapeType.RECTANGLE)
        self.width = w
        self.height = h

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

