# Utility module - provides helper functions and structs

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

def format_number(n: float, decimals: int) -> str:
    formatted: str = f"{n:.{decimals}f}"
    return formatted

def calculate_statistics(values: list[float]) -> tuple[float, int, float]:
    total: float = 0.0
    count: int = len(values)
    for v in values:
        total = total + v
    avg: float = 0.0
    if count > 0:
        avg = total / float(count)
    return (total, count, avg)

def shape_type_to_string(st: int) -> str:
    if st == 1:
        return "Circle"
    elif st == 2:
        return "Rectangle"
    elif st == 3:
        return "Triangle"
    else:
        return "Unknown"

