# Collections module - specialized collection classes

from shapes import IShape, ShapeBase
from utils import Point

class ShapeCollection:
    _shapes: list[IShape]
    _name: str

    def __init__(self, name: str):
        self._shapes = []
        self._name = name

    def add(self, shape: IShape) -> None:
        self._shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self._shapes:
            total = total + shape.area()
        return total

    def total_perimeter(self) -> float:
        total: float = 0.0
        for shape in self._shapes:
            total = total + shape.perimeter()
        return total

    def describe_all(self) -> None:
        for shape in self._shapes:
            if isinstance(shape, ShapeBase):
                base: ShapeBase = shape
                print(base.describe())

    def get_name(self) -> str:
        return self._name

class Point3D(Point):
    z: float

    def __init__(self, x: float, y: float, z: float):
        super().__init__(x, y)
        self.z = z

    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y + self.z * self.z) ** 0.5
